import { z } from "zod";
import { zodToJsonSchema } from "zod-to-json-schema";

export interface ToolDefinition {
    name: string;
    description: string;
    schema: any;
}

export interface ToolResult<T = any> {
    ok: boolean;
    error?: string;
    [key: string]: any;
}

export abstract class BaseTool<T> {
    abstract get name(): string;
    abstract get description(): string;
    abstract get schema(): z.ZodType<T>;

    abstract execute(args: T): Promise<ToolResult>;

    getToolDefinition(): ToolDefinition {
        const jsonSchema: any = zodToJsonSchema(this.schema, { target: "jsonSchema7" });
        return {
            name: this.name,
            description: this.description,
            schema: {
                type: "object",
                properties: jsonSchema.properties || {},
                required: jsonSchema.required || []
            }
        };
    }
}

import { PythonBridge } from "../bridge/python-bridge.js";

import chalk from "chalk";
import ora from "ora";
import { z } from "zod";



export interface AgentContext {
    task: string;
    maxSteps: number;
}

export class AgentLoop {
    constructor(private bridge: PythonBridge) {
    }

    async run(context: AgentContext): Promise<void> {
        const spinner = ora("Delegating task to Python Agent Engine...").start();

        try {
            const start = Date.now();
            const result = await this.bridge.call("agent_run", {
                user_input: context.task,
                max_steps: context.maxSteps
            }, 300000); // 5 min timeout for deep agent runs

            const elapsed = Date.now() - start;

            if (result.error) {
                spinner.fail(`Agent Engine failed: ${result.error}`);
                return;
            }

            spinner.succeed(`Task complete [took ${elapsed}ms]`);

            if (result.status === "success") {
                if (result.skill_used) {
                    console.log(chalk.cyan(`\n[Skill Used: ${result.skill_used}]`));
                }

                // Format if it's an object or string
                if (typeof result.output === 'object') {
                    console.log("\n" + chalk.green(JSON.stringify(result.output, null, 2)));
                } else {
                    console.log("\n" + chalk.green(result.output));
                }
            } else {
                console.log("\n" + chalk.yellow(JSON.stringify(result, null, 2)));
            }
        } catch (err: any) {
            spinner.fail(`Error communicating with Agent Engine: ${err.message}`);
            console.error(err);
        }
    }
}

import { spawn, ChildProcess } from "child_process";
import { createRequest, parseResponse, JsonRpcResponse } from "./protocol.js";
import * as path from "path";
import * as os from "os";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export class PythonBridge {
  private process: ChildProcess | null = null;
  private requestId = 0;
  private pending = new Map<number, { resolve: (v: any) => void; reject: (e: Error) => void }>();
  private buffer = "";

  isStarted(): boolean {
    return this.process !== null;
  }

  async start(): Promise<void> {
    if (this.process) return;

    const pythonDir = path.resolve(__dirname, "../../python");
    const pythonCmd = os.platform() === "win32" ? "python" : "python3";

    this.process = spawn(pythonCmd, ["-m", "aurex.main"], {
      cwd: pythonDir,
      stdio: ["pipe", "pipe", "pipe"],
      env: { ...process.env },
    });

    this.process.stderr!.on("data", (data: Buffer) => {
      const msg = data.toString().trim();
      if (msg) console.error(`[python-stderr] ${msg}`);
    });

    this.process.on("exit", (code) => {
      this.abortAll(new Error(`Python process exited with code ${code}`));
      this.process = null;
      process.off("SIGINT", this.handleSigint);
    });

    process.off("SIGINT", this.handleSigint);

    await new Promise<void>((resolve, reject) => {
      const timeout = setTimeout(() => cleanup(new Error("Python bridge timeout")), 10000);

      const cleanup = (err?: Error) => {
        clearTimeout(timeout);
        this.process?.stdout?.off("data", onReadyData);
        this.process?.off("error", onError);
        if (err) reject(err);
      };

      const onError = (err: Error) => cleanup(err);

      const onReadyData = (data: Buffer) => {
        this.buffer += data.toString("utf8");

        let newlineIdx = this.buffer.indexOf("\n");
        while (newlineIdx !== -1) {
          const line = this.buffer.slice(0, newlineIdx).trim();
          this.buffer = this.buffer.slice(newlineIdx + 1);

          if (!line) {
            newlineIdx = this.buffer.indexOf("\n");
            continue;
          }

          try {
            const parsed = JSON.parse(line);
            if (parsed?.ready === true) {
              clearTimeout(timeout);
              this.process!.stdout!.off("data", onReadyData);
              this.process!.stdout!.on("data", (d: Buffer) => {
                this.buffer += d.toString("utf8");
                this.processBuffer();
              });
              this.process!.off("error", onError);
              resolve();
              return;
            }

            console.error(`[python-stdout-preinit] ${line}`);
          } catch {
            console.error(`[python-stdout-preinit] ${line}`);
          }

          newlineIdx = this.buffer.indexOf("\n");
        }
      };

      this.process!.on("error", onError);
      this.process!.stdout!.on("data", onReadyData);
    });

    process.on("SIGINT", this.handleSigint);
  }

  private handleSigint = () => {
    this.abortAll(new Error("User interrupted operation"));
    this.stop();
  }

  private abortAll(error: Error) {
    for (const [, handler] of this.pending) {
      handler.reject(error);
    }
    this.pending.clear();
  }

  async call<T = any>(method: string, params: Record<string, unknown> = {}, timeoutMs = 60000): Promise<T> {
    if (!this.process) throw new Error("Python bridge not started");

    const id = ++this.requestId;
    const request = createRequest(method, params, id);

    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        if (this.pending.has(id)) {
          this.pending.delete(id);
          reject(new Error(`Python bridge request '${method}' timed out after ${timeoutMs}ms`));
        }
      }, timeoutMs);

      this.pending.set(id, {
        resolve: (value) => {
          clearTimeout(timeout);
          resolve(value);
        },
        reject: (error) => {
          clearTimeout(timeout);
          reject(error);
        },
      });

      this.process!.stdin!.write(request, (err) => {
        if (!err) return;
        clearTimeout(timeout);
        this.pending.delete(id);
        reject(err);
      });
    });
  }

  stop(): void {
    process.off("SIGINT", this.handleSigint);
    if (this.process) {
      const p = this.process;
      this.process = null;
      try { p.kill("SIGTERM"); } catch (e) { /* ignore */ }
      setTimeout(() => {
        try { p.kill("SIGKILL"); } catch (e) { /* ignore */ }
      }, 2000).unref();
    }
  }

  private processBuffer(): void {
    const lines = this.buffer.split("\n");
    this.buffer = lines.pop() || "";

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;

      try {
        const jsonStr = trimmed;
        // Strip out '{"ready": true}' or similar before standard parsing since they have been handled
        if (jsonStr === '{"ready": true}') continue;
        
        const response = parseResponse(jsonStr);
        const handler = this.pending.get(response.id);
        if (handler) {
          this.pending.delete(response.id);
          if (response.error) {
            handler.reject(new Error(response.error.message));
          } else {
            handler.resolve(response.result);
          }
        }
      } catch (e) {
        // Not JSON, probably a print() statement from Python
        console.error(`[python-stdout] ${trimmed}`);
      }
    }
  }
}

import * as readline from "readline";
import * as fs from "fs";
import * as os from "os";
import * as path from "path";
import chalk from "chalk";
import { PythonBridge } from "../bridge/python-bridge.js";
import { createExecutor } from "../executor/runner.js";
import { createVerifier } from "../verifier/test-runner.js";
import { readFile, writeFile } from "../editor/file-ops.js";
import { renderMarkdown, renderCitations } from "./renderer.js";
import { COMMANDS, getHelp } from "./commands.js";
import { createAppContext } from "../context.js";
import { setupBridgeHandlers } from "./setup-bridge.js";

const CONFIG_DIR = path.join(os.homedir(), ".config", "aurex");
if (!fs.existsSync(CONFIG_DIR)) {
  fs.mkdirSync(CONFIG_DIR, { recursive: true });
}
const HISTORY_FILE = path.join(CONFIG_DIR, "history");

function parseCommandArgs(input: string): string[] {
  const regex = /"([^"\\]*(?:\\.[^"\\]*)*)"|'([^'\\]*(?:\\.[^'\\]*)*)'|(\S+)/g;
  const matches = [];
  let match;
  while ((match = regex.exec(input)) !== null) {
    matches.push(match[1] || match[2] || match[3]);
  }
  return matches;
}

export async function startRepl(): Promise<void> {
  const bridge = new PythonBridge();
  const executor = createExecutor({});

  console.log(chalk.bold.cyan("\n  AurexAI v0.1.0"));
  console.log(chalk.gray("  Type /help for commands, Ctrl+C to exit\n"));

  try {
    await bridge.start();
  } catch (err) {
    console.log(chalk.yellow("  Python bridge not available. LLM/search features disabled."));
    console.log(chalk.gray("  Run: cd python && pip install -e .\n"));
  }

  const completer = (line: string) => {
    const completions = ["/help", "/search", "/exec", "/edit", "/test", "/plan", "/agent", "/read", "/fetch", "/exit"];
    const hits = completions.filter((c) => c.startsWith(line));
    return [hits.length ? hits : completions, line];
  };

  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    prompt: chalk.green("aurex> "),
    completer,
  });

  const appContext = createAppContext();

  appContext.modeManager.setConfirmFunction(async (msg) => {
    return new Promise<boolean>((resolve) => {
        rl.question(chalk.yellow(msg + " "), (ans: string) => {
            // @ts-ignore
            resolve(["y", "yes", "s", "sim"].includes(ans.trim().toLowerCase()));
        });
    });
  });

  setupBridgeHandlers(bridge, appContext, rl, {});

  // Load history
  if (fs.existsSync(HISTORY_FILE)) {
    try {
      const history = fs.readFileSync(HISTORY_FILE, "utf-8").split("\n").filter(Boolean);
      (rl as any).history = history.reverse(); // readline requires reversed array
    } catch {
      // Ignore history read errors
    }
  }

  rl.prompt();

  rl.on("line", async (line: string) => {
    const input = line.trim();
    if (!input) {
      rl.prompt();
      return;
    }

    try {
      if (input.startsWith("/")) {
        fs.appendFileSync(HISTORY_FILE, input + "\n");
        await handleCommand(input, bridge, executor);
      } else {
        fs.appendFileSync(HISTORY_FILE, input + "\n");
        await handleChat(input, bridge);
      }
    } catch (err: any) {
      console.log(chalk.red(`Error: ${err.message}`));
    }

    rl.prompt();
  });

  rl.on("close", () => {
    bridge.stop();
    console.log(chalk.gray("\nGoodbye!"));
    process.exit(0);
  });
}

async function handleCommand(
  input: string,
  bridge: PythonBridge,
  executor: ReturnType<typeof createExecutor>
): Promise<void> {
  const parts = parseCommandArgs(input.slice(1));
  const cmd = parts[0];
  const args = parts.slice(1).join(" "); // Re-join for backward compatibility with some commands, or they can use parts
  const parsedArgs = parts.slice(1);

  switch (cmd) {
    case "help":
      console.log(getHelp());
      break;

    case "search":
    case "s":
      if (!bridge.isStarted()) {
        console.log(chalk.yellow("  Search requires the Python bridge (LLM)."));
        break;
      }
      if (!args) {
        console.log(chalk.yellow("Usage: /search <query>"));
        break;
      }
      console.log(chalk.gray("Searching..."));
      const searchResults = await bridge.call("search", { query: args });
      renderCitations(searchResults.citations || []);
      break;

    case "exec":
    case "x":
      if (!args) {
        console.log(chalk.yellow("Usage: /exec <command>"));
        break;
      }
      console.log(chalk.gray(`Running: ${args}`));
      const result = await executor.run(args);
      if (result.stdout) console.log(result.stdout);
      if (result.stderr) console.log(chalk.red(result.stderr));
      console.log(chalk.gray(`Exit code: ${result.exitCode}`));
      break;

    case "edit":
    case "e":
      if (!bridge.isStarted()) {
        console.log(chalk.yellow("  Edit requires the Python bridge (LLM)."));
        break;
      }
      if (parsedArgs.length < 2) {
        console.log(chalk.yellow("Usage: /edit <file> <instruction>"));
        break;
      }
      const file = parsedArgs[0];
      const instruction = parsedArgs.slice(1).join(" ");
      console.log(chalk.gray(`Editing ${file}...`));
      const content = await readFile(file);
      const edited = await bridge.call("llm_chat", {
        messages: [
          { role: "system", content: "You are a code editor. Return ONLY the modified file content." },
          { role: "user", content: `File: ${file}\nInstruction: ${instruction}\n\nContent:\n${content}` },
        ],
      });
      await writeFile(file, edited.content);
      console.log(chalk.green(`Updated ${file}`));
      break;

    case "test":
    case "t":
      const verifier = createVerifier({});
      const testResults = await verifier.runPipeline();
      for (const r of testResults) {
        const icon = r.passed ? chalk.green("\u2713") : chalk.red("\u2717");
        console.log(`${icon} ${r.stage}: ${r.passed ? "PASSED" : "FAILED"}`);
      }
      break;



    case "plan":
    case "p":
      if (!args) {
        console.log(chalk.yellow("Usage: /plan <task description>"));
        break;
      }
      console.log(chalk.gray("Planning..."));
      const plan = await bridge.call("llm_plan", { task: args });
      renderMarkdown(plan.plan);
      break;

    case "agent":
    case "a":
      if (!bridge.isStarted()) {
        console.log(chalk.yellow("  Agent commands require the Python bridge (LLM)."));
        break;
      }
      if (!args) {
        console.log(chalk.yellow("Usage: /agent <task>"));
        break;
      }
      console.log(chalk.gray("Starting autonomous agent..."));
      const { AgentLoop } = await import("../agent/loop.js");
      const loop = new AgentLoop(bridge);
      await loop.run({ task: args, maxSteps: 15 });
      break;

    case "plan":
    case "p":
      if (!bridge.isStarted()) {
        console.log(chalk.yellow("  Plan requires the Python bridge (LLM)."));
        break;
      }
      if (!args) {
        console.log(chalk.yellow("Usage: /plan <goal>"));
        break;
      }
      console.log(chalk.gray(`Drafting plan for: ${args}`));
      await bridge.call("agent_plan", { task: args }, 300000);
      break;

    case "read":
    case "r":
      if (!args) {
        console.log(chalk.yellow("Usage: /read <file>"));
        break;
      }
      const fileContent = await readFile(args);
      console.log(fileContent);
      break;

    case "fetch":
    case "f":
      if (!bridge.isStarted()) {
        console.log(chalk.yellow("  Fetch requires the Python bridge."));
        break;
      }
      if (!args) {
        console.log(chalk.yellow("Usage: /fetch <url>"));
        break;
      }
      console.log(chalk.gray("Fetching..."));
      const fetched = await bridge.call("fetch_url", { url: args });
      console.log(fetched.content);
      break;

    case "exit":
    case "q":
      console.log(chalk.gray("\nGoodbye!"));
      process.exit(0);
      break;

    default:
      console.log(chalk.yellow(`Unknown command: /${cmd}. Type /help for available commands.`));
  }
}

async function handleChat(input: string, bridge: PythonBridge): Promise<void> {
  if (!bridge.isStarted()) {
    console.log(chalk.yellow("  Python bridge is not running. LLM features are disabled."));
    console.log(chalk.gray("  You can still use local tools like /exec, /read, etc."));
    return;
  }
  const response = await bridge.call("llm_chat", {
    messages: [{ role: "user", content: input }],
  });
  renderMarkdown(response.content);
}

import * as readline from "readline";
import chalk from "chalk";
import { PythonBridge } from "../bridge/python-bridge.js";
import { createExecutor, ExecutorConfig } from "../executor/runner.js";
import { AppContext } from "../context.js";
import {
    handleExec,
    handleReadFile,
    handleListFiles,
    handleEditFile,
    handleWriteFile,
    handleGrep,
    handleCreateAgent
} from "./tool-handlers.js";

export function setupBridgeHandlers(
  bridgeArg: PythonBridge,
  appContext: AppContext,
  rl?: readline.Interface,
  executorOptions?: ExecutorConfig
) {
    const bridge = bridgeArg as any;

    const ask = (q: string): Promise<string> => {
        return new Promise((resolve) => {
            if (process.env.AUREX_AUTO_YES === "1") {
                console.log(q + "y (auto)");
                return resolve("y");
            }
            if (rl) {
                rl.question(q, (ans) => {
                    setTimeout(() => resolve(ans), 0);
                });
            } else {
                const tempRl = readline.createInterface({ input: process.stdin, output: process.stdout });
                tempRl.question(q, (ans) => {
                    tempRl.close();
                    setTimeout(() => resolve(ans), 0);
                });
            }
        });
    };

    const executor = createExecutor({
        ...executorOptions,
        onLocalFallbackRequest: async (cmd: string) => {
            bridge.emit("pause_spinner");
            console.log(`\n${chalk.yellow(`ÔÜá SANDBOX FALHOU: O container Docker n├úo est├í dispon├¡vel.`)}`);
            const answer = await ask(`  Permitir execu├º├úo local do comando na sua m├íquina? (${cmd}) [y/N]: `);
            bridge.emit("resume_spinner");
            return ["y", "yes", "s", "sim"].includes(answer.trim().toLowerCase());
        }
    });

    bridge.on("request", async (req: any) => {
        if (req.method === "permission_request") {
            bridge.emit("pause_spinner");
            const { action, risk_level, reason } = req.params;
            const color = risk_level === "critical" ? chalk.red : (risk_level === "high" ? chalk.redBright : chalk.yellow);

            console.log(`\n${color(`ÔÜá CONFIRMA├ç├âO NECESS├üRIA [${risk_level.toUpperCase()}]`)}`);
            console.log(`  A├º├úo: ${action}`);
            console.log(`  Risco: ${reason}`);

            const answer = await ask(`  Permitir? [y/N]: `);
            const allowed = ["y", "yes", "s", "sim"].includes(answer.trim().toLowerCase());
            bridge.sendResponse(req.id, { allowed });
            bridge.emit("resume_spinner");
        } else if (req.method === "run_node_tool") {
            const { tool_name, tool_args } = req.params;
            bridge.emit("pause_spinner");
            try {
                if (!appContext.modeManager.isToolAllowed(tool_name)) {
                    throw new Error(`Tool ${tool_name} is blocked in current mode (${appContext.modeManager.getMode()})`);
                }

                let result;
                switch (tool_name) {
                    case "exec_command":
                        result = await handleExec(tool_args, executor);
                        break;
                    case "read_file":
                        result = await handleReadFile(tool_args);
                        break;
                    case "list_files":
                        result = await handleListFiles(tool_args);
                        break;
                    case "edit_file":
                        result = await handleEditFile(tool_args, ask);
                        break;
                    case "write_file":
                        result = await handleWriteFile(tool_args, ask);
                        break;
                    case "grep":
                        result = await handleGrep(tool_args);
                        break;
                    case "create_agent":
                        result = await handleCreateAgent(tool_args, ask);
                        break;
                    default:
                        throw new Error(`Unknown node tool: ${tool_name}`);
                }

                if (result.ok) {
                    appContext.honestyGuard.onToolExecuted({
                        id: req.id.toString(),
                        name: tool_name,
                        args: tool_args,
                        timestamp: Date.now()
                    });
                }

                bridge.sendResponse(req.id, result);
            } catch (err: unknown) {
                bridge.sendResponse(req.id, null, { code: -32000, message: (err as Error).message });
            } finally {
                bridge.emit("resume_spinner");
            }
        }
    });
}

import chalk from "chalk";
import * as diff from "diff";
import { readFile, writeFile } from "../editor/file-ops.js";
import { ToolResult } from "../agent/base-tool.js";

type AskFunction = (q: string) => Promise<string>;

export async function handleExec(tool_args: any, executor: any): Promise<ToolResult> {
    try {
        const runRes = await executor.run(tool_args.cmd);
        let finalStderr = runRes.stderr;
        if (runRes.exitCode !== 0 || runRes.timedOut) {
            const { isTransientError } = await import("../executor/retry.js");
            const isTransient = isTransientError({ stderr: runRes.stderr, code: runRes.exitCode, killed: runRes.timedOut });
            if (isTransient) {
                finalStderr = `[ErrorClass: TRANSIENT]\n${runRes.stderr}`;
            }
        }
        return { ok: runRes.exitCode === 0, stdout: runRes.stdout, stderr: finalStderr, exit_code: runRes.exitCode };
    } catch (cmdErr: any) {
        const { isTransientError } = await import("../executor/retry.js");
        const isTransient = isTransientError(cmdErr);
        return { ok: false, stdout: "", stderr: `[ErrorClass: ${isTransient ? 'TRANSIENT' : 'UNKNOWN'}]\n${cmdErr.message}`, exit_code: -1 };
    }
}

export async function handleReadFile(tool_args: any): Promise<ToolResult> {
    const content = await readFile(tool_args.path);
    return { ok: true, content: content.slice(0, 50000), truncated: content.length > 50000 };
}

export async function handleListFiles(tool_args: any): Promise<ToolResult> {
    const { listFiles } = await import("../editor/file-ops.js");
    const files = await listFiles(tool_args.dir || ".");
    return { ok: true, files: files.slice(0, 500), truncated: files.length > 500 };
}

export async function handleEditFile(tool_args: any, ask: AskFunction): Promise<ToolResult> {
    const filePath = tool_args.path;
    const oldText = tool_args.old_text;
    const newText = tool_args.new_text;
    const content = await readFile(filePath);

    if (!content.includes(oldText)) {
        return { ok: false, error: "old_text not found in file. Ensure it is an exact match including whitespace." };
    }

    const occurrences = content.split(oldText).length - 1;
    if (occurrences > 1 && !tool_args.replace_all) {
        return { ok: false, error: `old_text found ${occurrences} times. Provide more context to make it unique, or set replace_all: true.` };
    }

    const updated = tool_args.replace_all ? content.split(oldText).join(newText) : content.replace(oldText, newText);
    const diffLines = diff.diffLines(content, updated);
    let additions = 0, deletions = 0;
    diffLines.forEach((part: any) => {
        const lines = part.value.split('\n').filter((l: string) => l.length > 0).length;
        if (part.added) additions += lines;
        if (part.removed) deletions += lines;
    });

    console.log(`\n${chalk.cyan(`­ƒôä Patch ready for ${filePath}`)} ${chalk.green(`+${additions}`)} ${chalk.red(`-${deletions}`)}`);

    let allowed = false;
    while (true) {
        const answer = await ask(`  [a] apply   [d] view diff   [x] cancel: `);
        const cmd = answer.trim().toLowerCase();

        if (cmd === "a" || cmd === "y" || cmd === "yes") {
            allowed = true;
            break;
        } else if (cmd === "x" || cmd === "n" || cmd === "no") {
            allowed = false;
            break;
        } else if (cmd === "d" || cmd === "v") {
            console.log(`\n${chalk.cyan(`­ƒôä Diff:`)}`);
            diffLines.forEach((part: any) => {
                const color = part.added ? chalk.green : part.removed ? chalk.red : chalk.gray;
                const prefix = part.added ? "+ " : part.removed ? "- " : "  ";
                const lines = part.value.split('\n');
                if (lines[lines.length - 1] === '') lines.pop();
                lines.forEach((line: string) => console.log(color(prefix + line)));
            });
            console.log();
        }
    }

    if (!allowed) {
        return { ok: false, error: "User rejected the patch" };
    }
    await writeFile(filePath, updated);
    return { ok: true, message: `Edited ${filePath}`, replacements: tool_args.replace_all ? occurrences : 1 };
}

export async function handleWriteFile(tool_args: any, ask: AskFunction): Promise<ToolResult> {
    let content = "";
    try { content = await readFile(tool_args.path); } catch (e) {}

    const diffLines = diff.diffLines(content, tool_args.content);
    let additions = 0, deletions = 0;
    diffLines.forEach((part: any) => {
        const lines = part.value.split('\n').filter((l: string) => l.length > 0).length;
        if (part.added) additions += lines;
        if (part.removed) deletions += lines;
    });

    console.log(`\n${chalk.cyan(`­ƒôä File write ready for ${tool_args.path}`)} ${chalk.green(`+${additions}`)} ${chalk.red(`-${deletions}`)}`);

    let allowed = false;
    while (true) {
        const answer = await ask(`  [a] apply   [d] view diff   [x] cancel: `);
        const cmd = answer.trim().toLowerCase();

        if (cmd === "a" || cmd === "y" || cmd === "yes") {
            allowed = true;
            break;
        } else if (cmd === "x" || cmd === "n" || cmd === "no") {
            allowed = false;
            break;
        } else if (cmd === "d" || cmd === "v") {
            console.log(`\n${chalk.cyan(`­ƒôä Diff:`)}`);
            diffLines.forEach((part: any) => {
                const color = part.added ? chalk.green : part.removed ? chalk.red : chalk.gray;
                const prefix = part.added ? "+ " : part.removed ? "- " : "  ";
                const lines = part.value.split('\n');
                if (lines[lines.length - 1] === '') lines.pop();
                if (part.added || part.removed || lines.length <= 10) {
                    lines.forEach((line: string) => console.log(color(prefix + line)));
                } else {
                    lines.slice(0, 3).forEach((line: string) => console.log(color(prefix + line)));
                    console.log(chalk.gray("  ..."));
                    lines.slice(-3).forEach((line: string) => console.log(color(prefix + line)));
                }
            });
            console.log();
        }
    }

    if (!allowed) {
        return { ok: false, error: "User rejected the file write" };
    }
    await writeFile(tool_args.path, tool_args.content);
    return { ok: true, message: `Created/Overwritten ${tool_args.path}` };
}

export async function handleGrep(tool_args: any): Promise<ToolResult> {
    const { searchCode } = await import("../editor/search.js");
    const { getWorkspaceSandbox } = await import("../security/sandbox.js");
    const searchPath = tool_args.path || ".";
    const pattern = tool_args.pattern;

    if (!pattern || typeof pattern !== 'string') {
        return { ok: false, error: "Pattern is required for grep" };
    }

    const sandbox = getWorkspaceSandbox();

    const errorMsg = sandbox.validate(searchPath);
    if (errorMsg) {
        return { ok: false, error: errorMsg };
    }
    const resolvedDir = searchPath;

    const results = await searchCode(pattern, resolvedDir, { maxResults: 500 });
    const matches = results.map(r => `${r.file}:${r.line}:${r.content}`);
    const output = matches.join("\n");
    return {
        ok: true,
        matches: output.slice(0, 30000),
        truncated: matches.length >= 500 || output.length > 30000,
        count: matches.length,
        message: matches.length === 0 ? "No matches found" : undefined,
    };
}

