import * as fs from "fs";
import * as path from "path";
import yaml from "js-yaml";
import { fileURLToPath } from "url";
import { ConfigSchema, AurexConfig } from "./schema.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

let cachedConfig: AurexConfig | null = null;

export function loadConfig(configPath?: string): AurexConfig {
    if (cachedConfig && !configPath) return cachedConfig;

    // 1. Resolve config file path (defaults to project root config.yaml)
    const defaultPath = path.resolve(__dirname, "../../config.yaml");
    const targetPath = configPath || defaultPath;

    let fileConfig = {};

    // 2. Load YAML if it exists
    if (fs.existsSync(targetPath)) {
        try {
            const fileContent = fs.readFileSync(targetPath, "utf8");
            const parsed = yaml.load(fileContent) as any;
            if (parsed && typeof parsed === "object") {
                fileConfig = parsed;
            }
        } catch (err) {
            console.warn(`[config] Failed to parse ${targetPath}, using defaults.`);
        }
    } else if (!configPath && fs.existsSync(path.dirname(targetPath))) {
        // Automatically create config.yaml if it doesn't exist
        try {
            const defaults = ConfigSchema.parse({});
            fs.writeFileSync(targetPath, yaml.dump(defaults));
        } catch (e) {
            // ignore
        }
    }

    // 3. Override with Environment Variables (AUREX_*)
    applyEnvOverrides(fileConfig);

    // 4. Validate and apply defaults using Zod
    const result = ConfigSchema.safeParse(fileConfig);
    if (!result.success) {
        console.error("[config] Validation errors:");
        for (const error of result.error.errors) {
            console.error(`  - ${error.path.join('.')}: ${error.message}`);
        }
        // Return safe defaults if totally broken
        cachedConfig = ConfigSchema.parse({});
    } else {
        cachedConfig = result.data;
    }

    return cachedConfig;
}

function parseEnvValue(value: string): unknown {
    if (value === "true") return true;
    if (value === "false") return false;
    if (value.trim() !== "" && !Number.isNaN(Number(value))) return Number(value);
    return value;
}

function applyEnvOverrides(config: Record<string, any>) {
    const prefix = "AUREX_";
    const sections = ["executor", "verifier", "search", "llm", "repo_agent"] as const;

    for (const [key, value] of Object.entries(process.env)) {
        if (!key.startsWith(prefix) || !value) continue;

        const raw = key.slice(prefix.length);
        const section = sections.find((s) => raw === s.toUpperCase() || raw.startsWith(`${s.toUpperCase()}_`));
        if (!section) continue;

        const field = raw.slice(section.toUpperCase().length + 1).toLowerCase();
        if (!field) continue;

        if (!config[section]) config[section] = {};
        config[section][field] = parseEnvValue(value);
    }
}

// Automatically load on import
export const config = loadConfig();

import Dockerode from "dockerode";
import { config as appConfig } from "../config/loader.js";

const docker = new Dockerode();

export interface SandboxConfig {
  image: string;
  memoryLimit: string;
  cpuLimit: string;
  workDir: string;
  timeout: number;
}

const DEFAULT_CONFIG: SandboxConfig = {
  image: appConfig.executor.docker_image,
  memoryLimit: appConfig.executor.memory_limit,
  cpuLimit: appConfig.executor.cpu_limit,
  workDir: "/workspace",
  timeout: appConfig.executor.timeout_ms,
};

export interface SandboxResult {
  stdout: string;
  stderr: string;
  exitCode: number;
  timedOut: boolean;
  durationMs: number;
}

export async function runInSandbox(
  command: string,
  config: Partial<SandboxConfig> = {}
): Promise<SandboxResult> {
  const cfg = { ...DEFAULT_CONFIG, ...config };
  const startTime = Date.now();

  const container = await docker.createContainer({
    Image: cfg.image,
    Cmd: ["bash", "-c", command],
    WorkingDir: cfg.workDir,
    User: "1000:1000",
    HostConfig: {
      Memory: parseMemory(cfg.memoryLimit),
      NanoCpus: parseCpu(cfg.cpuLimit),
      NetworkMode: "none", // no network access in sandbox
      AutoRemove: true,
      ReadonlyRootfs: true,
      CapDrop: ["ALL"],
      SecurityOpt: ["no-new-privileges"],
      Binds: [
        `${process.cwd()}:${cfg.workDir}:ro`,
        // Also need temporary directory writable for many tools
      ],
      Tmpfs: {
        "/tmp": "rw,noexec,nosuid,size=64m",
        "/output": "rw,size=128m",
      },
    },
    Tty: false,
  });

  let stdout = "";
  let stderr = "";
  let timedOut = false;

  try {
    await container.start();

    const stream = await container.logs({ follow: true, stdout: true, stderr: true });

    const logPromise = new Promise<void>((resolve) => {
      stream.on("data", (chunk: Buffer) => {
        let offset = 0;
        while (offset < chunk.length) {
          // Docker multiplexed stream: first 8 bytes are header
          // [8] bytes header: [0] stream type, [4-7] payload size
          const type = chunk[offset];
          if (offset + 8 > chunk.length) break; // incomplete header

          const length = chunk.readUInt32BE(offset + 4);
          if (offset + 8 + length > chunk.length) break; // incomplete payload

          const payload = chunk.subarray(offset + 8, offset + 8 + length).toString();
          if (type === 1) stdout += payload;
          else if (type === 2) stderr += payload;

          offset += 8 + length;
        }
      });
      stream.on("end", resolve);
    });

    const timeoutPromise = new Promise<void>((resolve) => {
      setTimeout(async () => {
        timedOut = true;
        try {
          await container.kill();
        } catch { }
        resolve();
      }, cfg.timeout);
    });

    await Promise.race([logPromise, timeoutPromise]);

    const info = await container.inspect().catch(() => null);
    const exitCode = info?.State?.ExitCode ?? (timedOut ? 124 : 1);

    return {
      stdout: stdout.trim(),
      stderr: stderr.trim(),
      exitCode,
      timedOut,
      durationMs: Date.now() - startTime,
    };
  } catch (err: any) {
    return {
      stdout,
      stderr: err.message || "Container execution failed",
      exitCode: 1,
      timedOut: false,
      durationMs: Date.now() - startTime,
    };
  }
}

function parseMemory(limit: string): number {
  const match = limit.match(/^(\d+)([mg])$/i);
  if (!match) return 512 * 1024 * 1024;
  const val = parseInt(match[1]);
  return match[2].toLowerCase() === "g" ? val * 1024 * 1024 * 1024 : val * 1024 * 1024;
}

function parseCpu(limit: string): number {
  return Math.floor(parseFloat(limit) * 1e9);
}

export interface RetryConfig {
  maxAttempts: number;
  baseDelayMs: number;
  maxDelayMs: number;
  retryableErrors?: string[];
}

const DEFAULT_RETRY: RetryConfig = {
  maxAttempts: 3,
  baseDelayMs: 1000,
  maxDelayMs: 10000,
};

export async function withRetry<T>(
  fn: () => Promise<T>,
  config: Partial<RetryConfig> = {},
  shouldRetry?: (error: Error, attempt: number) => boolean
): Promise<T> {
  const cfg = { ...DEFAULT_RETRY, ...config };
  let lastError: Error | null = null;

  for (let attempt = 1; attempt <= cfg.maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err: any) {
      lastError = err;

      if (attempt >= cfg.maxAttempts) break;

      if (shouldRetry && !shouldRetry(err, attempt)) break;

      // Check if error is retryable
      if (cfg.retryableErrors && cfg.retryableErrors.length > 0) {
        const isRetryable = cfg.retryableErrors.some(
          (pattern) => err.message?.includes(pattern) || err.code === pattern
        );
        if (!isRetryable) break;
      }

      // Exponential backoff with jitter
      const delay = Math.min(
        cfg.baseDelayMs * Math.pow(2, attempt - 1) + Math.random() * 500,
        cfg.maxDelayMs
      );
      await sleep(delay);
    }
  }

  throw lastError || new Error("All retry attempts failed");
}

export function isTransientError(err: any): boolean {
  if (!err) return false;

  // Timeout from child_process
  if (err.killed === true) return true;
  if (err.timedOut === true) return true;

  // Network/Socket errors
  if (err.code === "ECONNRESET" || err.code === "ETIMEDOUT" || err.code === "ECONNREFUSED") return true;

  const msg = (err.message || "").toLowerCase();

  // Docker transient issues
  if (msg.includes("container not running") || msg.includes("timeout") || msg.includes("dead")) return true;

  // HTTP status
  if (msg.includes("429") || msg.includes("500") || msg.includes("502") || msg.includes("503") || msg.includes("504")) return true;

  // Do NOT retry on clear syntax/logic/missing errors
  if (msg.includes("enoent") || msg.includes("not found") || msg.includes("syntax error") || err.code === "ENOENT") {
    return false;
  }

  return false;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

import { exec } from "child_process";
import { promisify } from "util";
import { runInSandbox, SandboxResult } from "./docker-sandbox.js";
import { withRetry, isTransientError } from "./retry.js";
import { config as appConfig } from "../config/loader.js";

const execAsync = promisify(exec);

export interface ExecutorConfig {
  timeoutMs?: number;
  useSandbox?: boolean;
  maxRetries?: number;
  workDir?: string;
  onLocalFallbackRequest?: (command: string) => Promise<boolean>;
}

export interface ExecutionResult {
  stdout: string;
  stderr: string;
  exitCode: number;
  timedOut: boolean;
  durationMs: number;
  attempts: number;
}

export function createExecutor(config: ExecutorConfig = {}) {
  const {
    timeoutMs = appConfig.executor.timeout_ms,
    useSandbox = true,
    maxRetries = appConfig.executor.max_retries,
    workDir
  } = config;

  return {
    async run(command: string): Promise<ExecutionResult> {
      let attempts = 0;

      const execute = async (): Promise<ExecutionResult> => {
        attempts++;

        if (useSandbox) {
          try {
            const result = await runInSandbox(command, {
              timeout: timeoutMs,
              workDir: workDir || "/workspace",
            });
            // Treat non-zero exit from dockerode run as error to trigger retry
            if (result.timedOut || result.exitCode > 128) {
              throw Object.assign(new Error("Container failed"), { killed: result.timedOut, code: result.exitCode });
            }
            return { ...result, attempts };
          } catch (err: any) {
            // If Docker failed completely (transient), we throw to retry
            if (isTransientError(err)) throw err;
            // Otherwise Fallback to local if Docker not available
            console.warn(`\n[executor] Sandbox unavailable or failed (${err.message}).`);
            if (config.onLocalFallbackRequest) {
              const approved = await config.onLocalFallbackRequest(command);
              if (!approved) {
                throw new Error("Sandbox failed and local execution was not approved.");
              }
            } else {
              throw new Error("Sandbox failed and local execution requires explicit approval.");
            }
            console.warn(`\nWARNING: Running command directly on your machine: ${command}\n`);
            return runLocal(command, timeoutMs, attempts, workDir);
          }
        }

        return runLocal(command, timeoutMs, attempts, workDir);
      };

      return withRetry(execute, { maxAttempts: maxRetries }, (err, _attempt) => {
        return isTransientError(err);
      });
    },

    async runLocal(command: string): Promise<ExecutionResult> {
      return runLocal(command, timeoutMs, 1, workDir);
    },
  };
}

async function runLocal(command: string, timeoutMs: number, attempts: number, workDir?: string): Promise<ExecutionResult> {
  const startTime = Date.now();

  try {
    const { stdout, stderr } = await execAsync(command, {
      timeout: timeoutMs,
      maxBuffer: 10 * 1024 * 1024,
      cwd: workDir || process.cwd(),
    });

    return {
      stdout: stdout.trim(),
      stderr: stderr.trim(),
      exitCode: 0,
      timedOut: false,
      durationMs: Date.now() - startTime,
      attempts,
    };
  } catch (err: any) {
    return {
      stdout: err.stdout?.trim() || "",
      stderr: err.stderr?.trim() || err.message,
      exitCode: err.code ?? 1,
      timedOut: err.killed || false,
      durationMs: Date.now() - startTime,
      attempts,
    };
  }
}

