export async function runDoctor(_verbose: boolean = false): Promise<DoctorResult> {
  const checks: DoctorCheck[] = [];

  for (const check of DOCTOR_CHECKS) {
    try {
      const result = await check.check();
      checks.push(result);
    } catch (err: unknown) {
      checks.push({
        name: check.name,
        status: "error",
        message: `Check failed: ${(err as Error).message}`,
        lastChecked: Date.now(),
      });
    }
  }

  const allHealthy = checks.every(c => c.status === "ok");

  return { checks, allHealthy, timestamp: Date.now() };
}

/**
 * Print doctor results to console.
 */
export function printDoctorResult(result: DoctorResult): void {
  console.log(chalk.bold.cyan("\n­ƒ®║ Doctor / Healthcheck\n"));

  for (const check of result.checks) {
    const icon = check.status === "ok"
      ? chalk.green("Ô£ô")
      : check.status === "warn"
        ? chalk.yellow("ÔÜá")
        : chalk.red("Ô£ù");
    const statusColor = check.status === "ok"
      ? chalk.green
      : check.status === "warn"
        ? chalk.yellow
        : chalk.red;

    console.log(`  ${icon} ${chalk.bold(check.name.padEnd(15))} ${statusColor(check.message)}`);
  }

  const summary = result.allHealthy
    ? chalk.green("\n  Tudo saud├ível Ô£ô")
    : chalk.yellow(`\n  ${result.checks.filter((c: DoctorCheck) => c.status !== "ok").length} item(s) com aten├º├úo`);
  console.log(summary);
  console.log();
}

/**
 * plan-state.ts ÔÇö Plan state manager for AurexAI CLI Agent
 *
 * Tracks the active plan, its steps, and completion status.
 *
 * Reference: docs/architecture-reference/specs/memory.md ┬º3 PlanState
 */

import { v4 as uuidv4 } from "uuid";

// ÔöÇÔöÇÔöÇ Interfaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export type PlanStatus = 'draft' | 'approved' | 'in_progress' | 'completed' | 'failed';
export type StepStatus = 'pending' | 'in_progress' | 'completed' | 'skipped' | 'failed';

export interface PlanStep {
  id: string;
  description: string;
  status: StepStatus;
  toolsNeeded: string[];
  output: string | null;
  error: string | null;
}

export interface Plan {
  id: string;
  objective: string;
  steps: PlanStep[];
  affectedFiles: string[];
  risks: string[];
  status: PlanStatus;
  createdAt: number;
  completedAt: number | null;
}

// ÔöÇÔöÇÔöÇ Plan State Manager ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export class PlanStateManager {
  private activePlan: Plan | null = null;
  private history: Plan[] = [];

  /**
   * Create a new plan from an objective and steps.
   */
  createPlan(
    objective: string,
    steps: Array<{ description: string; toolsNeeded?: string[] }>,
    options?: { affectedFiles?: string[]; risks?: string[] }
  ): Plan {
    const plan: Plan = {
      id: uuidv4(),
      objective,
      steps: steps.map((s, i) => ({
        id: `step-${i + 1}`,
        description: s.description,
        status: 'pending' as StepStatus,
        toolsNeeded: s.toolsNeeded || [],
        output: null,
        error: null,
      })),
      affectedFiles: options?.affectedFiles || [],
      risks: options?.risks || [],
      status: 'draft',
      createdAt: Date.now(),
      completedAt: null,
    };

    this.activePlan = plan;
    return plan;
  }

  /**
   * Get the active plan.
   */
  getActivePlan(): Plan | null {
    return this.activePlan;
  }

  /**
   * Approve the active plan.
   */
  approvePlan(): boolean {
    if (!this.activePlan || this.activePlan.status !== 'draft') return false;
    this.activePlan.status = 'approved';
    return true;
  }

  /**
   * Start executing the plan.
   */
  startPlan(): boolean {
    if (!this.activePlan || this.activePlan.status !== 'approved') return false;
    this.activePlan.status = 'in_progress';
    return true;
  }

  /**
   * Mark a step as in-progress.
   */
  startStep(stepId: string): boolean {
    const step = this.findStep(stepId);
    if (!step || step.status !== 'pending') return false;
    step.status = 'in_progress';
    return true;
  }

  /**
   * Complete a step with output.
   */
  completeStep(stepId: string, output?: string): boolean {
    const step = this.findStep(stepId);
    if (!step) return false;
    step.status = 'completed';
    step.output = output || null;
    this.checkPlanCompletion();
    return true;
  }

  /**
   * Fail a step with error.
   */
  failStep(stepId: string, error: string): boolean {
    const step = this.findStep(stepId);
    if (!step) return false;
    step.status = 'failed';
    step.error = error;
    return true;
  }

  /**
   * Skip a step.
   */
  skipStep(stepId: string): boolean {
    const step = this.findStep(stepId);
    if (!step) return false;
    step.status = 'skipped';
    this.checkPlanCompletion();
    return true;
  }

  /**
   * Get the next pending step.
   */
  getNextStep(): PlanStep | null {
    if (!this.activePlan) return null;
    return this.activePlan.steps.find(s => s.status === 'pending') || null;
  }

  /**
   * Get progress as fraction.
   */
  getProgress(): { completed: number; total: number; percentage: number } {
    if (!this.activePlan) return { completed: 0, total: 0, percentage: 0 };
    const total = this.activePlan.steps.length;
    const completed = this.activePlan.steps.filter(
      s => s.status === 'completed' || s.status === 'skipped'
    ).length;
    return { completed, total, percentage: total > 0 ? (completed / total) * 100 : 0 };
  }

  /**
   * Fail the entire plan.
   */
  failPlan(_error?: string): void {
    if (!this.activePlan) return;
    this.activePlan.status = 'failed';
    this.activePlan.completedAt = Date.now();
    this.history.push(this.activePlan);
    this.activePlan = null;
  }

  /**
   * Clear the active plan.
   */
  clearPlan(): void {
    if (this.activePlan) {
      this.history.push(this.activePlan);
    }
    this.activePlan = null;
  }

  /**
   * Get plan history.
   */
  getHistory(): Plan[] {
    return [...this.history];
  }

  // ÔöÇÔöÇÔöÇ Private ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private findStep(stepId: string): PlanStep | null {
    return this.activePlan?.steps.find(s => s.id === stepId) || null;
  }

  private checkPlanCompletion(): void {
    if (!this.activePlan) return;
    const allDone = this.activePlan.steps.every(
      s => s.status === 'completed' || s.status === 'skipped'
    );
    if (allDone) {
      this.activePlan.status = 'completed';
      this.activePlan.completedAt = Date.now();
      this.history.push(this.activePlan);
      this.activePlan = null;
    }
  }
}

/**
 * dispatcher.ts ÔÇö Skill dispatcher for AurexAI CLI Agent
 *
 * Selects and executes skills, managing the lifecycle:
 * validate prerequisites ÔåÆ execute steps ÔåÆ handle errors ÔåÆ return result.
 *
 * Reference: docs/architecture-reference/specs/skill-user.md ┬º4
 */

import chalk from "chalk";
import { SkillDefinition, SkillStep, SkillLoader } from "./loader.js";
import { Mode } from "../agent/modes.js";

// ÔöÇÔöÇÔöÇ Interfaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface SkillContext {
  mode: Mode;
  inputs: Record<string, unknown>;
  availableTools: Set<string>;
  executor: {
    run(command: string): Promise<{ exitCode: number; stdout: string; stderr: string }>;
  };
}

export interface StepResult {
  stepId: string;
  success: boolean;
  output: string;
  error?: string;
  skipped?: boolean;
}

export interface SkillResult {
  skillName: string;
  success: boolean;
  steps: StepResult[];
  summary: string;
  durationMs: number;
}

export type SkillErrorRecovery = 'retry' | 'skip' | 'abort' | 'ask_user';

export interface SkillError {
  skillName: string;
  step: string;
  error: string;
  recovery: SkillErrorRecovery;
  suggestion: string;
}

// ÔöÇÔöÇÔöÇ Skill Dispatcher ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export class SkillDispatcher {
  constructor(private loader: SkillLoader) {}

  /**
   * Execute a skill by name with the given context.
   */
  async execute(skillName: string, context: SkillContext): Promise<SkillResult> {
    const skill = this.loader.get(skillName);
    if (!skill) {
      return {
        skillName,
        success: false,
        steps: [],
        summary: `Skill "${skillName}" n├úo encontrada. Use /skills para listar dispon├¡veis.`,
        durationMs: 0,
      };
    }

    return this.executeSkill(skill, context);
  }

  /**
   * Execute a specific skill definition.
   */
  async executeSkill(skill: SkillDefinition, context: SkillContext): Promise<SkillResult> {
    const start = Date.now();
    const stepResults: StepResult[] = [];

    // 1. Validate prerequisites
    const missingTools = skill.requiredTools.filter(t => !context.availableTools.has(t));
    if (missingTools.length > 0) {
      return {
        skillName: skill.name,
        success: false,
        steps: [],
        summary: `Skill "${skill.name}" requer tools n├úo dispon├¡veis: ${missingTools.join(', ')}`,
        durationMs: Date.now() - start,
      };
    }

    // 2. Validate required inputs
    const missingInputs = skill.inputs
      .filter(i => i.required && !(i.name in context.inputs))
      .map(i => i.name);
    if (missingInputs.length > 0) {
      return {
        skillName: skill.name,
        success: false,
        steps: [],
        summary: `Skill "${skill.name}" requer inputs: ${missingInputs.join(', ')}`,
        durationMs: Date.now() - start,
      };
    }

    // 3. Execute steps
    console.log(chalk.cyan(`\n­ƒöº Executando skill: ${skill.name}`));
    console.log(chalk.gray(`   ${skill.description}\n`));

    let aborted = false;

    for (const step of skill.steps) {
      if (aborted) break;

      // Check timeout
      const elapsed = Date.now() - start;
      if (elapsed > skill.limits.maxDuration * 1000) {
        stepResults.push({
          stepId: step.id,
          success: false,
          output: '',
          error: `Timeout: ultrapassou limite de ${skill.limits.maxDuration}s`,
        });
        break;
      }

      // Check condition
      if (step.condition && !this.evaluateCondition(step.condition, stepResults)) {
        stepResults.push({
          stepId: step.id,
          success: true,
          output: 'Condi├º├úo n├úo atendida, passo pulado',
          skipped: true,
        });
        continue;
      }

      console.log(chalk.gray(`   ÔåÆ Step ${step.id}: ${step.action}`));

      const stepResult = await this.executeStep(step, context, stepResults);
      stepResults.push(stepResult);

      if (!stepResult.success && !stepResult.skipped) {
        switch (step.onError) {
          case 'abort':
            console.log(chalk.red(`   Ô£ù Step ${step.id} falhou ÔÇö abortando skill`));
            if (step.errorMessage) console.log(chalk.yellow(`     ${step.errorMessage}`));
            aborted = true;
            break;
          case 'skip':
            console.log(chalk.yellow(`   ÔÜá Step ${step.id} falhou ÔÇö continuando`));
            break;
          case 'continue':
            console.log(chalk.yellow(`   ÔÜá Step ${step.id} falhou ÔÇö continuando`));
            break;
          case 'retry': {
            console.log(chalk.yellow(`   ÔÜá Step ${step.id} falhou ÔÇö tentando novamente`));
            const retryResult = await this.executeStep(step, context, stepResults);
            stepResults.push(retryResult);
            if (!retryResult.success) {
              console.log(chalk.red(`   Ô£ù Step ${step.id} falhou no retry ÔÇö abortando`));
              aborted = true;
            }
            break;
          }
          default:
            aborted = true;
        }
      } else if (stepResult.success && !stepResult.skipped) {
        console.log(chalk.green(`   Ô£ô Step ${step.id} conclu├¡do`));
      }
    }

    const allPassed = stepResults.filter(s => !s.skipped).every(s => s.success);
    const summary = allPassed
      ? `Skill "${skill.name}" executada com sucesso.`
      : `Skill "${skill.name}" completada com erros.`;

    console.log(allPassed
      ? chalk.green(`\n   Ô£ô ${summary}`)
      : chalk.yellow(`\n   ÔÜá ${summary}`)
    );

    return {
      skillName: skill.name,
      success: allPassed,
      steps: stepResults,
      summary,
      durationMs: Date.now() - start,
    };
  }

  /**
   * List all skills with formatting.
   */
  formatSkillList(availableTools: Set<string>): string {
    const statuses = this.loader.getAllWithStatus(availableTools);
    if (statuses.length === 0) {
      return chalk.gray("  Nenhuma skill encontrada. Adicione arquivos YAML em skills/");
    }

    const lines = [chalk.bold.cyan("\nSkills dispon├¡veis:\n")];
    for (const status of statuses) {
      const icon = status.available ? chalk.green("ÔùÅ") : chalk.yellow("Ôùï");
      const name = chalk.bold(status.skill.name.padEnd(25));
      const desc = chalk.gray(status.skill.description);
      const avail = status.available
        ? chalk.green("[dispon├¡vel]")
        : chalk.yellow(`[requer ${status.missingTools.join(', ')}]`);
      lines.push(`  ${icon} ${name} ${desc}  ${avail}`);
    }
    lines.push("");
    return lines.join("\n");
  }

  // ÔöÇÔöÇÔöÇ Private Methods ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async executeStep(
    step: SkillStep,
    context: SkillContext,
    _previousResults: StepResult[]
  ): Promise<StepResult> {
    try {
      // "none" tool means this step only produces output text
      if (!step.tool || step.tool === 'none') {
        return {
          stepId: step.id,
          success: true,
          output: step.output || step.action,
        };
      }

      // Shell command execution
      if (step.tool === 'shell' || step.tool === 'exec_command') {
        const cmd = this.interpolateCommand(step.command || '', context.inputs);
        const result = await context.executor.run(cmd);
        return {
          stepId: step.id,
          success: result.exitCode === 0,
          output: result.stdout || result.stderr || '',
          error: result.exitCode !== 0 ? (result.stderr || `Exit code: ${result.exitCode}`) : undefined,
        };
      }

      // File read
      if (step.tool === 'fs_read' || step.tool === 'read_file') {
        const { readFile } = await import("../editor/file-ops.js");
        const p = this.interpolateCommand(step.path || '', context.inputs);
        const content = await readFile(p);
        return {
          stepId: step.id,
          success: true,
          output: content.slice(0, 5000),
        };
      }

      // Default: unknown tool, just report
      return {
        stepId: step.id,
        success: false,
        output: '',
        error: `Tool "${step.tool}" n├úo suportado no dispatcher de skills`,
      };
    } catch (err: unknown) {
      return {
        stepId: step.id,
        success: false,
        output: '',
        error: (err as Error).message,
      };
    }
  }

  private interpolateCommand(template: string, inputs: Record<string, unknown>): string {
    return template.replace(/\{\{(\w+)\}\}/g, (_, key) => {
      return String(inputs[key] ?? '');
    });
  }

  private evaluateCondition(condition: string, results: StepResult[]): boolean {
    // Simple condition evaluator: "step.<id>.exit_code != 0"
    const match = condition.match(/step\.(\w+)\.(exit_code|success)\s*(!=|==)\s*(\d+|true|false)/);
    if (!match) return true; // can't evaluate, assume true

    const [, stepId, field, operator, value] = match;
    const step = results.find(r => r.stepId === stepId);
    if (!step) return true; // step hasn't run yet, assume true

    if (field === 'success') {
      const expectedBool = value === 'true';
      return operator === '==' ? step.success === expectedBool : step.success !== expectedBool;
    }

    // exit_code comparison (approximate: !success means non-zero)
    const exitCode = step.success ? 0 : 1;
    const expected = parseInt(value);
    return operator === '==' ? exitCode === expected : exitCode !== expected;
  }
}

/**
 * loader.ts ÔÇö Skill loader for AurexAI CLI Agent
 *
 * Loads skill definitions from YAML/MD files in the skills/ directory.
 * Supports both built-in skills (docs/architecture-reference/skills/)
 * and custom project skills (skills/ in workspace).
 *
 * Reference: docs/architecture-reference/specs/skill-user.md
 */

import * as fs from "fs/promises";
import * as path from "path";
import yaml from "js-yaml";

// ÔöÇÔöÇÔöÇ Interfaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface SkillTrigger {
  manual: boolean;
  auto: boolean;
  patterns: string[];
}

export interface SkillInput {
  name: string;
  type: string;
  required: boolean;
  description: string;
}

export interface SkillOutput {
  name: string;
  type: string;
  description: string;
}

export interface SkillStep {
  id: string;
  action: string;
  tool?: string;
  command?: string;
  path?: string;
  condition?: string;
  onError: 'retry' | 'skip' | 'abort' | 'continue' | 'ask_user';
  errorMessage?: string;
  output?: string;
}

export interface SkillLimits {
  maxDuration: number;       // seconds
  maxToolCalls: number;
  requiresApproval: boolean;
}

export interface SkillDefinition {
  name: string;
  version: string;
  description: string;
  trigger: SkillTrigger;
  requiredTools: string[];
  inputs: SkillInput[];
  outputs: SkillOutput[];
  steps: SkillStep[];
  limits: SkillLimits;
  source: string;           // file path where this was loaded from
}

export type ToolAvailability = 'available' | 'unavailable' | 'dev-only';

export interface SkillStatus {
  skill: SkillDefinition;
  available: boolean;
  missingTools: string[];
}

// ÔöÇÔöÇÔöÇ Skill Loader ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export class SkillLoader {
  private skills: Map<string, SkillDefinition> = new Map();
  private searchPaths: string[];

  constructor(searchPaths?: string[]) {
    this.searchPaths = searchPaths ?? [
      path.resolve("skills"),                   // project-level custom skills
    ];
  }

  /**
   * Load all skills from configured search paths.
   */
  async loadAll(): Promise<void> {
    for (const searchPath of this.searchPaths) {
      await this.loadFromDirectory(searchPath);
    }
  }

  /**
   * Load skills from a specific directory.
   */
  async loadFromDirectory(dirPath: string): Promise<void> {
    try {
      const entries = await fs.readdir(dirPath, { withFileTypes: true });
      for (const entry of entries) {
        if (!entry.isFile()) continue;
        const ext = path.extname(entry.name).toLowerCase();
        if (ext !== '.yaml' && ext !== '.yml' && ext !== '.md') continue;

        const filePath = path.join(dirPath, entry.name);
        try {
          const skill = await this.loadFile(filePath);
          if (skill) {
            this.skills.set(skill.name, skill);
          }
        } catch (err: unknown) {
          console.warn(`Warning: Failed to load skill from ${filePath}: ${(err as Error).message}`);
        }
      }
    } catch {
      // Directory doesn't exist, skip silently
    }
  }

  /**
   * Load a single skill from a file.
   */
  async loadFile(filePath: string): Promise<SkillDefinition | null> {
    const content = await fs.readFile(filePath, "utf-8");
    const ext = path.extname(filePath).toLowerCase();

    if (ext === '.yaml' || ext === '.yml') {
      return this.parseYaml(content, filePath);
    } else if (ext === '.md') {
      return this.parseMarkdown(content, filePath);
    }
    return null;
  }

  /**
   * Get all loaded skills.
   */
  getAll(): SkillDefinition[] {
    return Array.from(this.skills.values());
  }

  /**
   * Get a skill by name.
   */
  get(name: string): SkillDefinition | undefined {
    return this.skills.get(name);
  }

  /**
   * Check skill availability based on available tools.
   */
  checkAvailability(
    skill: SkillDefinition,
    availableTools: Set<string>
  ): SkillStatus {
    const missingTools = skill.requiredTools.filter(t => !availableTools.has(t));
    return {
      skill,
      available: missingTools.length === 0,
      missingTools,
    };
  }

  /**
   * Get all skills with availability status.
   */
  getAllWithStatus(availableTools: Set<string>): SkillStatus[] {
    return this.getAll().map(s => this.checkAvailability(s, availableTools));
  }

  /**
   * Find skills that match a given input text (for auto-triggering).
   */
  findMatchingSkills(input: string): SkillDefinition[] {
    return this.getAll().filter(skill => {
      if (!skill.trigger.auto) return false;
      return skill.trigger.patterns.some(pattern => {
        try {
          const regex = new RegExp(pattern, 'i');
          return regex.test(input);
        } catch {
          return input.toLowerCase().includes(pattern.toLowerCase());
        }
      });
    });
  }

  // ÔöÇÔöÇÔöÇ Private Parsers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private parseYaml(content: string, filePath: string): SkillDefinition {
    const raw = yaml.load(content) as unknown;
    return this.normalizeDefinition(raw, filePath);
  }

  private parseMarkdown(content: string, filePath: string): SkillDefinition | null {
    // Try to extract YAML frontmatter from markdown
    const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---/);
    if (!frontmatterMatch) {
      // Try to find a YAML code block
      const yamlBlock = content.match(/```ya?ml\n([\s\S]*?)```/);
      if (yamlBlock) {
        return this.parseYaml(yamlBlock[1], filePath);
      }
      return null;
    }
    return this.parseYaml(frontmatterMatch[1], filePath);
  }

  private normalizeDefinition(raw: any, filePath: string): SkillDefinition {
    return {
      name: raw.name || path.basename(filePath, path.extname(filePath)),
      version: String(raw.version || '1.0'),
      description: raw.description || '',
      trigger: {
        manual: raw.trigger?.manual ?? true,
        auto: raw.trigger?.auto ?? false,
        patterns: raw.trigger?.patterns ?? [],
      },
      requiredTools: raw.required_tools || raw.requiredTools || [],
      inputs: (raw.inputs || []).map((i: any) => ({
        name: i.name,
        type: i.type || 'string',
        required: i.required ?? false,
        description: i.description || '',
      })),
      outputs: (raw.outputs || []).map((o: any) => ({
        name: o.name,
        type: o.type || 'string',
        description: o.description || '',
      })),
      steps: (raw.steps || []).map((s: any) => ({
        id: s.id,
        action: s.action,
        tool: s.tool,
        command: s.command,
        path: s.path,
        condition: s.condition,
        onError: s.on_error || s.onError || 'abort',
        errorMessage: s.error_message || s.errorMessage,
        output: s.output,
      })),
      limits: {
        maxDuration: this.parseDuration(raw.limits?.max_duration) || 60,
        maxToolCalls: raw.limits?.max_tool_calls || 20,
        requiresApproval: raw.limits?.requires_approval ?? false,
      },
      source: filePath,
    };
  }

  private parseDuration(s: string | number | undefined): number {
    if (!s) return 60;
    if (typeof s === 'number') return s;
    const match = s.match(/^(\d+)(s|m|h)?$/);
    if (!match) return 60;
    const val = parseInt(match[1]);
    switch (match[2]) {
      case 'm': return val * 60;
      case 'h': return val * 3600;
      default: return val;
    }
  }
}

/**
 * runner.ts ÔÇö Subagent runner for AurexAI CLI Agent
 *
 * Executes subagents in isolated context. Each subagent gets its own
 * system prompt, restricted tool set, and token budget. Results are
 * returned as typed structures to the main agent loop.
 *
 * Reference: docs/architecture-reference/specs/architecture.md ┬º2.6
 */

import chalk from "chalk";
import {
  SubagentName,
  SubagentDefinition,
  SubagentTask,
  SubagentResult,
  SecurityReviewResult,
  ArchitectureReviewResult,
  ResearchResult,
  BugInvestigationResult,
  SUBAGENT_DEFINITIONS,
} from "./definitions.js";

// ÔöÇÔöÇÔöÇ Interfaces ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export interface SubagentExecutionConfig {
  /** Available tool implementations that subagent can use */
  toolExecutor: {
    readFile: (path: string) => Promise<string>;
    listFiles: (pattern: string) => Promise<string[]>;
    grep: (pattern: string, dir: string) => Promise<string[]>;
    runCommand: (cmd: string) => Promise<{ exitCode: number; stdout: string; stderr: string }>;
  };

  /** Optional LLM call for deep analysis (when available) */
  llmCall?: (systemPrompt: string, userMessage: string) => Promise<string>;

  /** Max execution time in ms */
  timeout?: number;

  /** Verbose logging */
  verbose?: boolean;
}

export interface SubagentRunResult {
  subagent: SubagentName;
  success: boolean;
  result: SubagentResult | null;
  rawOutput: string;
  durationMs: number;
  tokensUsed: number;
  error?: string;
}

// ÔöÇÔöÇÔöÇ Subagent Runner ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export class SubagentRunner {
  private config: SubagentExecutionConfig;

  constructor(config: SubagentExecutionConfig) {
    this.config = config;
  }

  /**
   * Run a subagent by name with a task.
   */
  async run(name: SubagentName, task: SubagentTask): Promise<SubagentRunResult> {
    const definition = SUBAGENT_DEFINITIONS[name];
    if (!definition) {
      return {
        subagent: name,
        success: false,
        result: null,
        rawOutput: "",
        durationMs: 0,
        tokensUsed: 0,
        error: `Subagent "${name}" n├úo encontrado`,
      };
    }

    console.log(chalk.cyan(`\n­ƒñû Delegando para subagent: ${chalk.bold(name)}`));
    console.log(chalk.gray(`   ${definition.specialty}`));
    console.log(chalk.gray(`   Tarefa: ${task.task}\n`));

    const start = Date.now();
    const timeout = this.config.timeout ?? 120_000; // 2 min default

    try {
      // If we have an LLM, use it for deep analysis
      if (this.config.llmCall) {
        return await this.runWithLLM(definition, task, start, timeout);
      }

      // Otherwise, run deterministic analysis
      return await this.runDeterministic(definition, task, start);
    } catch (err: unknown) {
      return {
        subagent: name,
        success: false,
        result: null,
        rawOutput: "",
        durationMs: Date.now() - start,
        tokensUsed: 0,
        error: (err as Error).message,
      };
    }
  }

  /**
   * Run with LLM for deep analysis.
   */
  private async runWithLLM(
    def: SubagentDefinition,
    task: SubagentTask,
    start: number,
    timeout: number
  ): Promise<SubagentRunResult> {
    const userMessage = this.buildUserMessage(task);

    // Create a timeout promise
    const timeoutPromise = new Promise<never>((_, reject) => {
      setTimeout(() => reject(new Error(`Timeout: subagent "${def.name}" excedeu ${timeout / 1000}s`)), timeout);
    });

    const llmPromise = this.config.llmCall!(def.systemPrompt, userMessage);
    const rawOutput = await Promise.race([llmPromise, timeoutPromise]);
    const tokensUsed = Math.ceil(rawOutput.length / 4);

    // Try to parse structured result
    const result = this.parseResult(def.name, rawOutput);

    console.log(result
      ? chalk.green(`   Ô£ô Subagent ${def.name} concluiu com sucesso`)
      : chalk.yellow(`   ÔÜá Subagent ${def.name} retornou resultado n├úo-estruturado`)
    );

    return {
      subagent: def.name,
      success: true,
      result,
      rawOutput,
      durationMs: Date.now() - start,
      tokensUsed,
    };
  }

  /**
   * Run deterministic analysis (no LLM, uses tools directly).
   */
  private async runDeterministic(
    def: SubagentDefinition,
    task: SubagentTask,
    start: number
  ): Promise<SubagentRunResult> {
    const executor = this.config.toolExecutor;

    switch (def.name) {
      case "security-reviewer":
        return this.runSecurityReview(task, start, executor);
      case "architecture-reviewer":
        return this.runArchitectureReview(task, start, executor);
      case "researcher":
        return this.runResearch(task, start);
      case "bug-investigator":
        return this.runBugInvestigation(task, start, executor);
      default:
        return {
          subagent: def.name,
          success: false,
          result: null,
          rawOutput: "",
          durationMs: Date.now() - start,
          tokensUsed: 0,
          error: `An├ílise determin├¡stica n├úo dispon├¡vel para "${def.name}". Requer LLM.`,
        };
    }
  }

  // ÔöÇÔöÇÔöÇ Deterministic Implementations ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async runSecurityReview(
    task: SubagentTask,
    start: number,
    executor: SubagentExecutionConfig["toolExecutor"]
  ): Promise<SubagentRunResult> {
    const findings: any[] = [];
    const files = task.files ?? [];

    // Get files to scan
    let targetFiles = files;
    if (targetFiles.length === 0) {
      try {
        targetFiles = await executor.listFiles("**/*.{ts,js,py,json,yaml,yml,env}");
        targetFiles = targetFiles.slice(0, 50); // limit
      } catch { targetFiles = []; }
    }

    // Scan for common security issues
    const SECURITY_PATTERNS = [
      { pattern: "password\\s*=\\s*['\"]", category: "Secrets", severity: "CRITICAL" as const, desc: "Senha hardcoded" },
      { pattern: "api[_-]?key\\s*=\\s*['\"]", category: "Secrets", severity: "CRITICAL" as const, desc: "API key hardcoded" },
      { pattern: "secret\\s*=\\s*['\"]", category: "Secrets", severity: "HIGH" as const, desc: "Secret hardcoded" },
      { pattern: "eval\\(", category: "Injection", severity: "HIGH" as const, desc: "Uso de eval()" },
      { pattern: "innerHTML", category: "XSS", severity: "MEDIUM" as const, desc: "Uso de innerHTML" },
      { pattern: "execSync\\(", category: "Command Injection", severity: "MEDIUM" as const, desc: "execSync sem sanitiza├º├úo" },
      { pattern: "\\.env", category: "Config", severity: "INFO" as const, desc: "Refer├¬ncia a .env" },
    ];

    for (const pattern of SECURITY_PATTERNS) {
      try {
        const grepResults = await executor.grep(pattern.pattern, ".");
        for (const line of grepResults.slice(0, 5)) {
          const match = line.match(/^(.+):(\d+):/);
          if (match) {
            findings.push({
              severity: pattern.severity,
              category: pattern.category,
              file: match[1],
              line: parseInt(match[2]),
              description: pattern.desc,
              impact: `Potencial vulnerabilidade: ${pattern.category}`,
              recommendation: `Revisar uso de ${pattern.pattern.replace(/\\\\/g, '')} neste contexto`,
              codeExample: "",
            });
          }
        }
      } catch { /* grep failed, skip */ }
    }

    const result: SecurityReviewResult = {
      summary: {
        totalFindings: findings.length,
        critical: findings.filter((f: any) => f.severity === "CRITICAL").length,
        high: findings.filter((f: any) => f.severity === "HIGH").length,
        medium: findings.filter((f: any) => f.severity === "MEDIUM").length,
        low: findings.filter((f: any) => f.severity === "LOW").length,
        info: findings.filter((f: any) => f.severity === "INFO").length,
      },
      findings,
      passed: findings.filter((f: any) => f.severity === "CRITICAL" || f.severity === "HIGH").length === 0,
      recommendations: [],
    };

    console.log(chalk.green(`   Ô£ô Security review: ${findings.length} findings`));

    return {
      subagent: "security-reviewer",
      success: true,
      result: { type: "security-review", data: result },
      rawOutput: JSON.stringify(result, null, 2),
      durationMs: Date.now() - start,
      tokensUsed: 0,
    };
  }

  private async runArchitectureReview(
    task: SubagentTask,
    start: number,
    executor: SubagentExecutionConfig["toolExecutor"]
  ): Promise<SubagentRunResult> {
    // Collect metrics
    let allFiles: string[] = [];
    try {
      allFiles = await executor.listFiles("**/*.{ts,js}");
    } catch { /* no files */ }

    let totalLines = 0;
    const fileSizes: number[] = [];
    const imports: Record<string, string[]> = {};

    const fileStats = await Promise.all(
      allFiles.slice(0, 30).map(async (file) => {
        try {
          const content = await executor.readFile(file);
          const lines = content.split("\n").length;
          const importMatches = content.match(/from\s+["']\.+\/([^"']+)["']/g) || [];
          const parsedImports = importMatches.map((m: string) => m.replace(/from\s+["']/, "").replace(/["']/, ""));
          return { lines, imports: parsedImports, file };
        } catch { return null; }
      })
    );

    for (const stat of fileStats) {
      if (stat) {
        totalLines += stat.lines;
        fileSizes.push(stat.lines);
        imports[stat.file] = stat.imports;
      }
    }

    const avgSize = fileSizes.length > 0 ? Math.round(totalLines / fileSizes.length) : 0;

    const result: ArchitectureReviewResult = {
      assessment: `Projeto com ${allFiles.length} arquivos TypeScript/JavaScript, m├®dia de ${avgSize} linhas por arquivo.`,
      strengths: [
        "Separa├º├úo em m├│dulos por responsabilidade",
        "Tipagem TypeScript com strict mode",
        "Testes unit├írios presentes",
      ],
      concerns: fileSizes.filter((s: number) => s > 300).length > 0 ? [{
        severity: "medium",
        area: "File size",
        issue: `${fileSizes.filter((s: number) => s > 300).length} arquivo(s) com mais de 300 linhas`,
        impact: "Arquivos grandes s├úo mais dif├¡ceis de manter",
        recommendation: "Considerar extrair em m├│dulos menores",
        files: [],
      }] : [],
      patterns: {
        detected: ["modular-architecture", "dependency-injection"],
        recommended: [],
        antiPatterns: [],
      },
      metrics: {
        moduleCount: allFiles.length,
        avgFileSize: avgSize,
        maxComplexity: { file: "", function: "", complexity: 0 },
        circularDependencies: [],
      },
    };

    console.log(chalk.green(`   Ô£ô Architecture review: ${allFiles.length} modules analyzed`));

    return {
      subagent: "architecture-reviewer",
      success: true,
      result: { type: "architecture-review", data: result },
      rawOutput: JSON.stringify(result, null, 2),
      durationMs: Date.now() - start,
      tokensUsed: 0,
    };
  }

  private async runResearch(
    task: SubagentTask,
    start: number
  ): Promise<SubagentRunResult> {
    // Research requires LLM + web search, return informative error
    const result: ResearchResult = {
      query: task.task,
      summary: "Pesquisa requer LLM e ferramentas de web search para resultados completos.",
      findings: [],
      sources: [],
      limitations: ["Sem acesso a web_search neste momento"],
      suggestions: ["Configurar API key de LLM para pesquisa completa"],
    };

    console.log(chalk.yellow(`   ÔÜá Research requer LLM ÔÇö retornando resultado parcial`));

    return {
      subagent: "researcher",
      success: true,
      result: { type: "research", data: result },
      rawOutput: JSON.stringify(result, null, 2),
      durationMs: Date.now() - start,
      tokensUsed: 0,
    };
  }

  private async runBugInvestigation(
    task: SubagentTask,
    start: number,
    executor: SubagentExecutionConfig["toolExecutor"]
  ): Promise<SubagentRunResult> {
    const result: BugInvestigationResult = {
      summary: `Investiga├º├úo de: ${task.task}`,
      reproduction: {
        steps: ["Tentativa de reprodu├º├úo autom├ítica"],
        command: task.stackTrace ? `Baseado no stack trace: ${task.stackTrace}` : "npm test",
        output: "",
        reproduced: false,
      },
      hypotheses: [],
      rootCause: {
        file: "",
        line: 0,
        description: "Investiga├º├úo requer LLM para an├ílise profunda",
        confidence: 0,
        evidence: [],
      },
      fix: {
        diff: "",
        explanation: "Investiga├º├úo completa requer LLM",
        risks: [],
        testCommand: "npm test",
      },
      relatedIssues: [],
      regressionSince: null,
    };

    // If we have a stack trace, try to extract file info
    if (task.stackTrace) {
      const fileMatch = task.stackTrace.match(/at\s+\w+\s+\((.+):(\d+)/);
      if (fileMatch) {
        result.rootCause.file = fileMatch[1];
        result.rootCause.line = parseInt(fileMatch[2]);
        try {
          const content = await executor.readFile(fileMatch[1]);
          const lines = content.split("\n");
          const lineNum = parseInt(fileMatch[2]) - 1;
          result.rootCause.description = `Erro na linha ${fileMatch[2]}: ${lines[lineNum]?.trim() || ""}`;
          result.rootCause.confidence = 0.5;
          result.rootCause.evidence.push(`Conte├║do da linha: ${lines[lineNum]?.trim()}`);
        } catch { /* file not accessible */ }
      }
    }

    // Try to reproduce
    if (task.error) {
      try {
        const testResult = await executor.runCommand("npm test 2>&1 | head -50");
        result.reproduction.output = testResult.stdout.slice(0, 2000);
        result.reproduction.reproduced = testResult.exitCode !== 0;
      } catch { /* test failed */ }
    }

    console.log(chalk.green(`   Ô£ô Bug investigation: ${result.hypotheses.length} hypotheses`));

    return {
      subagent: "bug-investigator",
      success: true,
      result: { type: "bug-investigation", data: result },
      rawOutput: JSON.stringify(result, null, 2),
      durationMs: Date.now() - start,
      tokensUsed: 0,
    };
  }

  // ÔöÇÔöÇÔöÇ Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private buildUserMessage(task: SubagentTask): string {
    const parts = [`Tarefa: ${task.task}`];
    if (task.scope) parts.push(`Escopo: ${task.scope}`);
    if (task.files?.length) parts.push(`Arquivos: ${task.files.join(", ")}`);
    if (task.error) parts.push(`Erro: ${task.error}`);
    if (task.stackTrace) parts.push(`Stack trace: ${task.stackTrace}`);
    if (task.context) parts.push(`Contexto: ${JSON.stringify(task.context)}`);
    return parts.join("\n");
  }

  private parseResult(name: SubagentName, raw: string): SubagentResult | null {
    // Try to extract JSON from the response
    const jsonMatch = raw.match(/```json\n([\s\S]*?)```/) || raw.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return null;

    try {
      const jsonStr = jsonMatch[1] || jsonMatch[0];
      const data = JSON.parse(jsonStr);

      switch (name) {
        case "security-reviewer":
          return { type: "security-review", data: data as SecurityReviewResult };
        case "architecture-reviewer":
          return { type: "architecture-review", data: data as ArchitectureReviewResult };
        case "researcher":
          return { type: "research", data: data as ResearchResult };
        case "bug-investigator":
          return { type: "bug-investigation", data: data as BugInvestigationResult };
      }
    } catch {
      return null;
    }
  }

  /**
   * List available subagents.
   */
  static listSubagents(): SubagentDefinition[] {
    return Object.values(SUBAGENT_DEFINITIONS);
  }

  /**
   * Format subagent list for display.
   */
  static formatList(): string {
    const lines = [chalk.bold.cyan("\n­ƒñû Subagents dispon├¡veis:\n")];
    for (const def of Object.values(SUBAGENT_DEFINITIONS)) {
      lines.push(`  ${chalk.bold(def.name.padEnd(25))} ${chalk.gray(def.specialty)}`);
      lines.push(`  ${chalk.gray("Tools:")} ${def.tools.join(", ")}`);
      lines.push("");
    }
    return lines.join("\n");
  }
}

/**
 * preview.ts ÔÇö Preview manager for AurexAI CLI Agent
